var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"젠장, 또 먹통이야! 이런 고물 무전기 같으니!","JPN":"ちくしょう、また使えなくなったわ！　このポンコツ無線機！","ENG":"Dang it! It's not working again! A piece of junk radio!","TWN":"該死，又故障了！這個老古董！"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"자동차 걷어차지 마! 사고 난다고!","JPN":"おいおい、車は蹴るなよ！　事故っちゃうぞ？","ENG":"Stop kicking the car! You'll cause an accident!","TWN":"別踢汽車了！會出事的！"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그보다 답신은? 다른 소대에서 뭐래?","JPN":"返信は？　他の小隊はなんだって？","ENG":"What about the responses? What do the other squads say?","TWN":"得到回覆了嗎？其他小隊說什麼？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"퍽이나 답신이 오겠다. 무전이 제대로 갔는지도 모르는데.","JPN":"返信なんかくるわけないでしょ。無線がちゃんと届いたかもわからないのに。","ENG":"You really think there will be any responses? I'm not even sure if my message got through.","TWN":"現在都不知道無線電有沒有正常發出去，說什麼說啊。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그럼 큰일난 거 아냐? 점점 따라 잡히고 있다고!","JPN":"それってまずくねえか？　だんだん追いつかれてきてるんだぞ！","ENG":"Then we're screwed, aren't we? That thing is catching up to us real fast!","TWN":"那怎麼辦？我們快被追上了！"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그러니까 처음부터 내 말대로 했어야지, 인간 암컷.","JPN":"だから最初からオルカの言うことを聞けばよかったんだ、のろまなメス。","ENG":"You should have heeded my words, human female.","TWN":"所以剛才就應該聽我說的做了啊，人類女孩。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"지금이라도 늦지 않았어.","JPN":"今からでも遅くない。","ENG":"It's not too late.","TWN":"現在也不晚。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"차를 세워라! 내가 놈을 도륙해 주지!","JPN":"車を止めろ！　オルカが奴をズタズタにしてやる！","ENG":"Stop the car at once! I shall shred them to smithereens!","TWN":"停車！我去解決掉它！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"말했잖아? 네가 전면에 나서면 CRF 소모가 너무 크다고!","JPN":"言ったでしょ？　あんたが本気出すとCRFの消耗が激しすぎるって！","ENG":"Didn't I tell you? If you engage, you'll use up too much CRF!","TWN":"我不是說過了嗎？你如果投入戰鬥CRF消耗太大！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"무슨 상관이지?","JPN":"それがなに？","ENG":"Should I care?","TWN":"跟你有什麼關係？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이 몸은 이제 내 것이다. 내 마음대로 할 수 있는 거라고!","JPN":"この体はもうオルカのもの。自分の好きなようにできる！","ENG":"This body belongs to me now. I can do with it as I please!","TWN":"這個身體現在是我的。我可以隨意支配！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"젠장, 네가 소모한 CRF를 채워 줄 이터니움은 우리가 벌고 있잖아.","JPN":"だから、あんたが消耗したCRFを満たすエタニウムはこっちが稼いでいるわけよ。","ENG":"We're the ones earning the Eternium to refill the CRF you keep using up, darn it!","TWN":"喂，你消耗完CRF，還不是要靠我們賺永恆之金來填充。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"쓸데없이 낭비를 하면 할수록 간식을 사는 데 쓸 예산도 줄어든다고.","JPN":"無駄に使いまくったらおやつ代の予算が減るんだよ？　いいの？","ENG":"If you waste it willy-nilly, we won't have enough money to buy snacks.","TWN":"別隨便浪費，不然買零食的預算也少了。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"새, 생각해 보니 저런 하찮은 놈을 내가 직접 상대할 필요는 없겠지.","JPN":"よ、よく考えたらあの程度の奴、オルカが直接相手する必要はなさそうだ。","ENG":"C-come to think of it, I suppose there's no need to personally engage such a petty creature.","TWN":"好，好吧，那種傢伙的確不需要我親自出手。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"난 바쁜 일이 있어서 내려가 있겠다.","JPN":"ちょっと急用ができたから下がっておく。","ENG":"I shall retire for now, as I'm rather busy with another matter.","TWN":"我還有事，先下去了。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"내 몸이 다치지 않게 잘 지키도록, 인간!","JPN":"この体が怪我しないようちゃんと守れよ、人間！","ENG":"Take good care of my flesh, human!","TWN":"好好保護這個身體，人類女孩！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......바쁜 일은 또 뭐야? 머릿속에 비밀 친구들이라도 만들었어?","JPN":"……急用ってなによ？　頭の中で秘密の友達でも作ったの？","ENG":"Busy with what? You got a bunch of imaginary friends coming for a tea party in your head?","TWN":"……你是怎麼了？難道是在自己腦海中交了什麼秘密朋友嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};